async function post(table, rows) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=slug`, {
    method: "POST",
    headers: {
      apikey: SUPABASE_KEY,
      Authorization: `Bearer ${SUPABASE_KEY}`,
      "Content-Type": "application/json",
      Prefer: "return=minimal,resolution=merge-duplicates",
    },
    body: JSON.stringify(rows),
  });
  if (!res.ok) {
    const t = await res.text();
    console.error(`  ERROR ${res.status}: ${t.slice(0, 200)}`);
    return false;
  }
  return true;
}

function e(slug, title, summary, type, domain, tags, metadata = {}, body = "") {
  return {
    slug, title: { en: title }, summary: { en: summary },
    body: body ? { en: body } : { en: "" },
    entity_type: type, domain: "construction", status: "published",
    tags, metadata, source_urls: [],
  };
}

